import{_ as e,o as i,c as r,a2 as l}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"📊 市場情緒日報 — 2026-05-07（週四）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/市場情緒/市場情緒_2026-05-07.md","filePath":"Deep32Q知識庫/市場情緒/市場情緒_2026-05-07.md"}'),o={name:"Deep32Q知識庫/市場情緒/市場情緒_2026-05-07.md"};function t(n,a,s,h,d,c){return i(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="📊-市場情緒日報-—-2026-05-07-週四" tabindex="-1">📊 市場情緒日報 — 2026-05-07（週四） <a class="header-anchor" href="#📊-市場情緒日報-—-2026-05-07-週四" aria-label="Permalink to &quot;📊 市場情緒日報 — 2026-05-07（週四）&quot;">​</a></h1><blockquote><p>查詢時間：2026-05-07 05:00 TST（= 2026-05-06 21:00 UTC）</p></blockquote><hr><h2 id="🔟-十點重點摘要" tabindex="-1">🔟 十點重點摘要 <a class="header-anchor" href="#🔟-十點重點摘要" aria-label="Permalink to &quot;🔟 十點重點摘要&quot;">​</a></h2><h3 id="_1-🇺🇸-美伊和談曙光-油價暴跌、市場風險偏好回升" tabindex="-1">1. 🇺🇸 美伊和談曙光：油價暴跌、市場風險偏好回升 <a class="header-anchor" href="#_1-🇺🇸-美伊和談曙光-油價暴跌、市場風險偏好回升" aria-label="Permalink to &quot;1. 🇺🇸 美伊和談曙光：油價暴跌、市場風險偏好回升&quot;">​</a></h3><p>美國與伊朗接近達成一頁備忘錄（MoU），結束衝突並啟動核談判。Axios 報導白宮正與德黑蘭協商，伊朗可能接受強化 UN 核查、暫停濃縮 12-15 年。此消息帶動全球市場風險偏好大幅回升。</p><ul><li><strong>來源</strong>：Axios (2026-05-06)、Barchart (2026-05-06)</li></ul><h3 id="_2-🛢️-原油單日暴跌近-9-wti-跌至-95、brent-跌破-102" tabindex="-1">2. 🛢️ 原油單日暴跌近 9%：WTI 跌至 $95、Brent 跌破 $102 <a class="header-anchor" href="#_2-🛢️-原油單日暴跌近-9-wti-跌至-95、brent-跌破-102" aria-label="Permalink to &quot;2. 🛢️ 原油單日暴跌近 9%：WTI 跌至 $95、Brent 跌破 $102&quot;">​</a></h3><p>美伊和談進展令原油大幅回落。WTI 原油跌至約 $95/桶（日內一度觸及 $88.66），Brent 原油跌至約 $101-103/桶，跌幅逾 7%。霍爾木茲海峽重開預期是主因。</p><ul><li><strong>來源</strong>：TradingEconomics (2026-05-06)、Forbes (2026-05-06)、LA Times (2026-05-06)</li></ul><h3 id="_3-📈-美股期貨走高-nasdaq-100-期貨漲逾-1" tabindex="-1">3. 📈 美股期貨走高：Nasdaq 100 期貨漲逾 1% <a class="header-anchor" href="#_3-📈-美股期貨走高-nasdaq-100-期貨漲逾-1" aria-label="Permalink to &quot;3. 📈 美股期貨走高：Nasdaq 100 期貨漲逾 1%&quot;">​</a></h3><p>受 AMD 強勁財報（Q1 超預期 + Q2 展望亮眼）及美伊和談樂觀情緒帶動，Nasdaq 100、道瓊、S&amp;P 500 期貨均上漲。歐洲 Euro Stoxx 50 指數 5/6 收漲逾 2%。</p><ul><li><strong>來源</strong>：Barchart (2026-05-06)、247WallSt (2026-05-06)、TipRanks (2026-05-06)</li></ul><h3 id="_4-🇹🇼-台股再創歷史新高-加權指數突破-41-000-點" tabindex="-1">4. 🇹🇼 台股再創歷史新高：加權指數突破 41,000 點 <a class="header-anchor" href="#_4-🇹🇼-台股再創歷史新高-加權指數突破-41-000-點" aria-label="Permalink to &quot;4. 🇹🇼 台股再創歷史新高：加權指數突破 41,000 點&quot;">​</a></h3><p>5/6 台股加權指數收漲 369 點至 41,138 點（+0.91%），連三日上漲再創歷史新高。三大法人合計買超 672.75 億元。台指期貨夜盤一度衝破 42,000 點，台積電期貨盤後報 2320 點（+2.65%）。</p><ul><li><strong>來源</strong>：RTHK (2026-05-06)、CNYES (2026-05-06)</li></ul><h3 id="_5-💵-美元指數跌至-98-附近-fed-維持利率不變後走弱" tabindex="-1">5. 💵 美元指數跌至 98 附近：Fed 維持利率不變後走弱 <a class="header-anchor" href="#_5-💵-美元指數跌至-98-附近-fed-維持利率不變後走弱" aria-label="Permalink to &quot;5. 💵 美元指數跌至 98 附近：Fed 維持利率不變後走弱&quot;">​</a></h3><p>美元指數 DXY 5/6 跌至約 98.02-98.04，為近兩個月低位。Fed 在 4/29 維持利率 3.50%-3.75% 不變後，美元持續承壓。Norges Bank、Riksbank、Banxico 均將於 5/7 公布利率決議。</p><ul><li><strong>來源</strong>：TradingView (2026-05-06)、TradingEconomics (2026-05-06)、CNYES (2026-05-06)</li></ul><h3 id="_6-🥇-金價攀至-4-691-受避險需求與實質利率下降支撐" tabindex="-1">6. 🥇 金價攀至 $4,691：受避險需求與實質利率下降支撐 <a class="header-anchor" href="#_6-🥇-金價攀至-4-691-受避險需求與實質利率下降支撐" aria-label="Permalink to &quot;6. 🥇 金價攀至 $4,691：受避險需求與實質利率下降支撐&quot;">​</a></h3><p>XAU/USD 升至 $4,691.03（+2.96%），盤中一度觸及 $4,700 以上。美伊和談雖降低地緣風險，但油價下跌帶動通膨預期降溫、美債殖利率走低，反而利好黃金。美元走弱亦提供支撐。</p><ul><li><strong>來源</strong>：TradingEconomics (2026-05-06)、Investing.com (2026-05-06)</li></ul><h3 id="_7-⚠️-霍爾木茲海峽仍高度不確定-470-艘船受-gps-干擾" tabindex="-1">7. ⚠️ 霍爾木茲海峽仍高度不確定：470 艘船受 GPS 干擾 <a class="header-anchor" href="#_7-⚠️-霍爾木茲海峽仍高度不確定-470-艘船受-gps-干擾" aria-label="Permalink to &quot;7. ⚠️ 霍爾木茲海峽仍高度不確定：470 艘船受 GPS 干擾&quot;">​</a></h3><p>儘管伊朗宣稱將提供安全通行，但霍爾木茲海峽及阿曼灣航行條件「急劇惡化」。約 470 艘船遭 GPS 干擾，AIS 關閉普遍。5/4 阿聯酋富查伊拉 VTTI 石油碼頭遭攻擊。法國船隻在海峽遇襲。</p><ul><li><strong>來源</strong>：OPB (2026-05-06)、GTReview (2026-05-06)、CFR (2026-05-06)</li></ul><h3 id="_8-📊-企業財報季強勁-s-p-500-連續六季雙位數獲利成長" tabindex="-1">8. 📊 企業財報季強勁：S&amp;P 500 連續六季雙位數獲利成長 <a class="header-anchor" href="#_8-📊-企業財報季強勁-s-p-500-連續六季雙位數獲利成長" aria-label="Permalink to &quot;8. 📊 企業財報季強勁：S&amp;P 500 連續六季雙位數獲利成長&quot;">​</a></h3><p>2026 Q1 財報季表現亮眼，S&amp;P 500 預計連續第六個季度實現雙位數獲利成長。科技、原物料、金融、工業類股獲利顯著增長。AMD 財報超預期是近期市場催化劑。</p><ul><li><strong>來源</strong>：Forex.com (2026-05-06)、SeekingAlpha (2026-05-06)</li></ul><h3 id="_9-📅-本週焦點-adp-就業報告-5-7-非農-5-9" tabindex="-1">9. 📅 本週焦點：ADP 就業報告（5/7）+ 非農（5/9） <a class="header-anchor" href="#_9-📅-本週焦點-adp-就業報告-5-7-非農-5-9" aria-label="Permalink to &quot;9. 📅 本週焦點：ADP 就業報告（5/7）+ 非農（5/9）&quot;">​</a></h3><p>投資人關注即將公布的 4 月 ADP 就業報告（5/7），作為週五非農就業數據的前導指標。市場預期將影響 Fed 6 月利率決策方向。</p><ul><li><strong>來源</strong>：ThinkCapital (2026-05-06)、TradingCharts (2026-05-07)</li></ul><h3 id="_10-🏦-央行利率決議日-norges-bank、riksbank、banxico-5-7-公布" tabindex="-1">10. 🏦 央行利率決議日：Norges Bank、Riksbank、Banxico 5/7 公布 <a class="header-anchor" href="#_10-🏦-央行利率決議日-norges-bank、riksbank、banxico-5-7-公布" aria-label="Permalink to &quot;10. 🏦 央行利率決議日：Norges Bank、Riksbank、Banxico 5/7 公布&quot;">​</a></h3><p>5/7 三大央行同日公布利率決議。墨西哥央行（Banxico）可能因經濟成長擔憂再度降息。市場關注各央行政策方向對匯率的影響。</p><ul><li><strong>來源</strong>：ThinkCapital (2026-05-06)、MUFG Research (2026-05-01)</li></ul><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>Barchart (2026-05-06): Nasdaq 期貨上漲，AMD 財報與美伊和談樂觀情緒</li><li>247WallSt (2026-05-06): 科技股因晶片強勁與油價下跌而飆升</li><li>TradingEconomics (2026-05-06): WTI $95.05、Brent $101.67、DXY 98.02、Gold $4,691.03</li><li>RTHK (2026-05-06): 台股加權指數 41,138 點、三大法人買超 672 億</li><li>Axios (2026-05-06): 美伊接近達成一頁備忘錄</li><li>OPB/CFR (2026-05-06): 霍爾木茲海峽 470 艘船受 GPS 干擾</li><li>Forbes (2026-05-06): 原油價格大幅回落</li><li>ThinkCapital (2026-05-06): 本週經濟日曆焦點</li><li>Forex.com (2026-05-06): S&amp;P 500 連續六季雙位數獲利成長</li><li>MUFG Research (2026-05-01): 央行利率決策展望</li></ol>',37)])])}const _=e(o,[["render",t]]);export{p as __pageData,_ as default};
